INSERT INTO reports (ts,reporter_name,candidate_name,candidate_grade,first_chief,first_note,s_motivation,s_total,draft,plan,checker,status,acquired_ka) VALUES ('08/07 3:06','津山','森 圭吾','3年生','','礼儀正しく、ひとつひとつの行動が丁寧です。自分から何か生み出すことは苦手そうですが、指示に対して100%で返してくれる。',4,6,'もう少し様子見','あと1年早ければチーフに育てられる存在だと感じます。楽屋番など安心して任せられるメンツにしたい。稼働率次第で声かけようと思ってます。','','checked',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('森 圭吾',' ',''),'　','') LIMIT 1),''));
