INSERT INTO reports (ts,reporter_name,candidate_name,candidate_grade,first_chief,first_note,s_motivation,s_total,draft,plan,checker,status,acquired_ka) VALUES ('08/30 23:31','高橋慶多','金子聡志','1年生','高田','コミュニケーション能力が高く、教えたことを周りに共有しスムーズに作業をしているのが非常に好印象でした。初めて会った時から声を出すことが出来るし、物覚えが早く積極的に仕事に取り組むのでチーフになれると思いました。',4,8,'あげる','サンガのセクションチーフ。自分で考えて、チーフにも相談できる能力が素晴らしいと思うので、サンガを引っ張ってもらいたい。','髙田','checked',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('金子聡志',' ',''),'　','') LIMIT 1),''));
INSERT INTO reports (ts,reporter_name,candidate_name,candidate_grade,first_chief,first_note,s_motivation,s_total,draft,plan,checker,status,acquired_ka) VALUES ('09/01 21:07','乾','高橋 虎太郎','1年生','連絡無し→現場決まり次第連絡予定','指示への理解が早く、積極的に仕事に取り組んでくれていた。 他の新人の子達を巻き込んで、作業を行ったり他のサボっている子に対して、注意していたところがとても一年生とは思えないくらいしっかりしていた。 松井・佐藤がこの子は良かったという発言もあり、次期チーフとして育てていきたいと思うような子でした。',4,7,'あげる','人をまとめる力があると思われるので、搬入出頭など簡単なところから始めたい。ゆくゆくはサブチーフ、チーフまで育成したいと考えてます。','松井','checked',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('高橋 虎太郎',' ',''),'　','') LIMIT 1),''));
