INSERT INTO reports (ts,reporter_name,candidate_name,candidate_grade,first_note,status,acquired_ka) VALUES ('07/13','佐藤→ガンバ班(國分)','林 汰一','3年生','[発見現場:キュウソネコカミ@INTEX / 現場回数:5回以下] アーティスト物販の最後尾を任せていたが、自分が見れていなくても、長い列の蛇行を綺麗に組んでいた。片付け時も空気を読んで柵を固めたりなど率先してやってくれていた。新3回生で今後続けるかは曖昧、','pending',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('林 汰一',' ',''),'　','') LIMIT 1),''));
