INSERT INTO reports (ts,reporter_name,candidate_name,candidate_grade,first_note,status,acquired_ka) VALUES ('07/13','津山','小西瑛士','4回生','[発見現場:嵐ロビデコ@グラングリーン / 現場回数:20回越え] 広報の仕方や業務への姿勢など、メンツとしての素質が十分備わっている。4回生ですが、稼働率を見込めるため獲得希望です。','pending',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('小西瑛士',' ',''),'　','') LIMIT 1),''));
INSERT INTO reports (ts,reporter_name,candidate_name,candidate_grade,first_note,status,acquired_ka) VALUES ('07/13','津山','大地遥斗','2回生','[発見現場:音道楽@GLION / 現場回数:10回程度] 真面目なタイプで静かな印象ですが、お客様へ寄り添うような案内の仕方をしていて丁寧な子だと感じました。','pending',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('大地遥斗',' ',''),'　','') LIMIT 1),''));
INSERT INTO reports (ts,reporter_name,candidate_name,candidate_grade,first_note,status,acquired_ka) VALUES ('07/13','佐藤','西部 翔琉','3回生','[発見現場:B''z@OCC / 現場回数:20回越え] 城ホの物販で入り口に2日間ついてもらっていたが，丁寧な対応と広報もしてくれていた．現場回数は多いがチームのシステムがわかっていなくてこれまで入っていなかった．これから辞めるつもりもないみたい．','pending',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('西部 翔琉',' ',''),'　','') LIMIT 1),''));
INSERT INTO reports (ts,reporter_name,candidate_name,candidate_grade,first_note,status,acquired_ka) VALUES ('07/13','坂本','伊谷渉真','不明','[発見現場:メトロック / 現場回数:5回以下] メトロック入口で入ってた子です。客出し中と片付けのときに指示に対する理解力が高かった。業務にも協力的でテキパキ動くタイプ。落ち着いて話す時間を取れず、学年の確認やLINE交換まではできずです、','pending',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('伊谷渉真',' ',''),'　','') LIMIT 1),''));
INSERT INTO reports (ts,reporter_name,candidate_name,candidate_grade,first_note,status,acquired_ka) VALUES ('07/13','髙田','湯谷亮洋','1回生','[発見現場:音道楽@GLION / 現場回数:10回程度] ミーティングを聞く姿勢が他の人とは違いました。業務に関しても分からないことは質問してくれたり、コミュニケーションもしっかり取れたりと、自分の中で物事を考えて仕事をしてくれてます。','pending',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('湯谷亮洋',' ',''),'　','') LIMIT 1),''));
INSERT INTO reports (ts,reporter_name,candidate_name,candidate_grade,first_note,status,acquired_ka) VALUES ('07/13','髙田','林汰一','3回生','[発見現場:M1@GLION / 現場回数:10回程度] 最前管理をしていましたが、通りかかるスタッフさんへの挨拶を欠かさず、椅子バラ後の片付けにも率先して自分で動き、分からないことは都度聞いてくれて丁寧だと感じた。院進予定で将来性もある。','pending',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('林汰一',' ',''),'　','') LIMIT 1),''));
INSERT INTO reports (ts,reporter_name,candidate_name,candidate_grade,first_note,status,acquired_ka) VALUES ('07/13','津山','中谷陽斗','2回生','[発見現場:NiziU@ドーム / 現場回数:20回越え] 昨年末からずっと目を付けていた子です。愛想が良く、メリハリをつけて仕事ができる子だと思います。チームに入る意欲が出てきているため、絶対とります。','pending',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('中谷陽斗',' ',''),'　','') LIMIT 1),''));
INSERT INTO blacklist (ts,date,reporter,name,s_talk,s_dress,s_groom,s_late,s_work,reason,added_by,matched_ka) VALUES ('10/29','10/29','相尾','熊谷 拓真',2,4,4,2,4,'挙動不審な印象。受け答えははきはきしているが、慌ただしい。 遅刻癖がある。バスで来るため遅延が多い。言い訳にならないとは自分で言うているものの直らない。 追記:メガネの子？この子はダメやと思います（佐藤）一生懸命だが、あかん(？)','相尾',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('熊谷 拓真',' ',''),'　','') LIMIT 1),''));
INSERT INTO blacklist (ts,date,reporter,name,s_talk,s_dress,s_groom,s_late,s_work,reason,added_by,matched_ka) VALUES ('10/28','10/28','相尾','和田 空大',3,2,3,3,2,'スーツで白靴下着用。客止めの内止めもできない。 客だし終わった後に片付けもせず、舞台の搬出に混ざろうとする。（理由：みんながいるから）','相尾',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('和田 空大',' ',''),'　','') LIMIT 1),''));
INSERT INTO blacklist (ts,date,reporter,name,s_talk,s_dress,s_groom,s_late,s_work,reason,added_by,matched_ka) VALUES ('10/30','10/30','酒井','遠山 暖大',3,3,2,4,2,'ネイキッドで発見。基本誰にでもタメ語ベースで、失礼な印象。ジャンパーが小さいのか、ジッパー全開に何度注意してもしてしまう。また、「そこのライト付いてる看板運んで」と言う指示で、ベンチを運ぼうとする。根本何も考えていない。間仕切りなどのポジションも危うい印象を受けた。','酒井',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('遠山 暖大',' ',''),'　','') LIMIT 1),''));
INSERT INTO blacklist (ts,date,reporter,name,s_talk,s_dress,s_groom,s_late,s_work,reason,added_by,matched_ka) VALUES ('11/3','11/3','佐藤','田中 恭一',3,4,3,2,3,'Ballet Muses@東大阪で発見。遅刻から始まり、休憩時も時間通りに戻って来れない。その事について聞くと「ほんまっすか」みたいな感じ。','佐藤',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('田中 恭一',' ',''),'　','') LIMIT 1),''));
INSERT INTO blacklist (ts,date,reporter,name,s_talk,s_dress,s_groom,s_late,s_work,reason,added_by,matched_ka) VALUES ('11/18','11/18','佐藤','河合 飛佳',3,3,2,4,2,'ネイキッドで発見。自分が横にいる時でも柵に寄りかかったり手をついたり落ち着きがない。指示した内容も全く頭に入ってない。現場回数は50回以上と多いものの接客業をする上でかなり欠けている部分が多い気がする。','佐藤',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('河合 飛佳',' ',''),'　','') LIMIT 1),''));
INSERT INTO blacklist (ts,date,reporter,name,s_talk,s_dress,s_groom,s_late,s_work,reason,added_by,matched_ka) VALUES ('12/1','12/1','佐藤','山口 和也',2,2,3,2,3,'自身がビーイングやっていてワースト3に入るくらいの人物。現場回数50弱にも関わらず、ジャージ,ロゴ入り,グレーズボンで遅刻してきて、タメ口混じりの敬語。こりゃダメ','佐藤',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('山口 和也',' ',''),'　','') LIMIT 1),''));
INSERT INTO blacklist (ts,date,reporter,name,s_talk,s_dress,s_groom,s_late,s_work,reason,added_by,matched_ka) VALUES ('12/20','12/20','津山','中村 玲勇',2,4,4,4,2,'間仕切りレクチャーしっかりやりましたが、楽屋に客を入れて問題になりました。事情聴取時、「誰でも入れていいよと言われました」と謎発言されました。話が通じない子です。クソです','津山',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('中村 玲勇',' ',''),'　','') LIMIT 1),''));
INSERT INTO blacklist (ts,date,reporter,name,s_talk,s_dress,s_groom,s_late,s_work,reason,added_by,matched_ka) VALUES ('12/20','12/20','津山','藤本 蒼士',3,4,3,4,2,'レクチャー時から舐めた態度を取った後、間仕切りで足を組む。社員に見つかった際も足を直そうとしなかったことから、仕事をしているという意識が皆無だと思われます。','津山',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('藤本 蒼士',' ',''),'　','') LIMIT 1),''));
INSERT INTO blacklist (ts,date,reporter,name,s_talk,s_dress,s_groom,s_late,s_work,reason,added_by,matched_ka) VALUES ('12/20','12/20','津山','長友 一馬',2,3,4,4,2,'女性無線持ちがロビーにいといてと言ったのに勝手にどこかへ行き、勝手に迷子になっていました。その女の子はアイツ話通じひん、ほんまにNGで、だそうです。','津山',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('長友 一馬',' ',''),'　','') LIMIT 1),''));
INSERT INTO blacklist (ts,date,reporter,name,s_talk,s_dress,s_groom,s_late,s_work,reason,added_by,matched_ka) VALUES ('1/9','1/9','酒井','市田 拓海',2,4,4,4,2,'シンプルにやってと言っていることができない。頭も悪い。何を考えているかわからない。30年後街中で急に大声出す奴になりそう。','酒井',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('市田 拓海',' ',''),'　','') LIMIT 1),''));
INSERT INTO blacklist (ts,date,reporter,name,s_talk,s_dress,s_groom,s_late,s_work,reason,added_by,matched_ka) VALUES ('1/11','1/11','佐藤','狩峰 遥仁',2,4,4,4,2,'JUMP＠KDOで発見、EV間仕切り配置だったが勤務設定時間になったら勝手に控室に戻る（理由：勤務設定時間過ぎて忘れられてると思ったから←開演中に2回も休憩回したにも関わらず） 現場回数20回くらいなのにチーフ,控室管理に名前も言わないで勝手に帰った→会社から本人に連絡してもらってドームに帰還させた ミーティング中も全く関係ない方向を向いたり、直接話した際も何を言ってるのかわからない','佐藤',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('狩峰 遥仁',' ',''),'　','') LIMIT 1),''));
INSERT INTO blacklist (ts,date,reporter,name,s_talk,s_dress,s_groom,s_late,s_work,reason,added_by,matched_ka) VALUES ('1/18','1/18','岡本','西田 凌',4,2,2,3,4,'香西かおり@テクスピア大阪で発見。現場回数80回以上にも関わらず、スニーカーソックス着用してるだけでなく黒スニーカーでいいと思い込んでいた。20秒に1回ぐらい大あくびしていて印象も悪い。人前に出せない子です。','岡本',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('西田 凌',' ',''),'　','') LIMIT 1),''));
INSERT INTO blacklist (ts,date,reporter,name,s_talk,s_dress,s_groom,s_late,s_work,reason,added_by,matched_ka) VALUES ('1/26','1/26','坂本','無量井 翔平',3,4,4,4,2,'1/26キンプリ@KDOで発見。座席の案内もあやふや。開演中に方杖をついて座っていた。間仕切り配置でも不安な印象。','坂本',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('無量井 翔平',' ',''),'　','') LIMIT 1),''));
INSERT INTO blacklist (ts,date,reporter,name,s_talk,s_dress,s_groom,s_late,s_work,reason,added_by,matched_ka) VALUES ('2/1','2/1','坂本','六信 怜士',3,3,3,4,2,'なにわ@KDOで発見。開演中、足を広げ柵にもたれかかって座っている。何度注意しても目を離したらすぐ足を広げる。マスクを鼻出しでつけており、注意しても、外すなり、しっかり着用するなりができない。名札台紙も白黒のモノを使用しており、指摘されるまで違和感を感じていなかった。 立ち姿勢もすぐダレ、終演後も急に通り合わせ部隊から抜けるなど、案内業務以外にも危うさを感じた。','坂本',COALESCE((SELECT ka FROM users WHERE REPLACE(REPLACE(name,' ',''),'　','')=REPLACE(REPLACE('六信 怜士',' ',''),'　','') LIMIT 1),''));
